    let color = 'var(--text-muted)';
    if (['css', 'scss', 'less', 'h', 'hpp'].includes(ext)) color = '#3b82f6';
    else if (['txt', 'log'].includes(ext)) color = '#ec4899';
    else if (['java', 'jar', 'kt', 'kts'].includes(ext)) color = '#b91c1c';
    else if (['png', 'jpg', 'jpeg', 'gif', 'svg', 'webp'].includes(ext)) color = '#10b981';
    else if (['cs', 'csharp'].includes(ext)) color = '#10b981';
    else if (['php'].includes(ext)) color = '#8b5cf6';
    else if (['rb', 'ruby'].includes(ext)) color = '#ef4444';
    else if (['sh', 'bash', 'zsh'].includes(ext)) color = '#22c55e';
    else if (['yaml', 'yml', 'toml', 'ini'].includes(ext)) color = '#f59e0b';
    else if (['xml'].includes(ext)) color = '#3b82f6';
    else if (['sql'].includes(ext)) color = '#06b6d4';
    else if (['dart'].includes(ext)) color = '#0284c7';
    else if (['swift'].includes(ext)) color = '#f97316';
    else if (['lua'].includes(ext)) color = '#3b82f6';
    else if (['dockerfile', 'ignore', 'lock'].includes(ext) || lowerName.includes('dockerfile')) color = '#0284c7';
    
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" class="w-4 h-4 shrink-0"><path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/></svg>`;
